                if((x&mask)<=val0 && val0<y){

                    int z = ba[i].rank(r,0) - ba[i].rank(l,0);

                    int l0 = ba[i].rank(l,0), r0 = l0+z;

                    if(r0-l0>0) stk.emplace(l0,r0,i-1,val0);

                }

            }

        }



        return ret;

    }



