    uint64_t access(int pos){

        uint64_t ret = 0;

        for(int i=LOGA; i>=0; --i){

            int b = ba[i].access(pos);

            if(b){

                pos = nzero[i] + ba[i].rank(pos,1);

            }

            else{

                pos = ba[i].rank(pos,0);

            }

            ret = (ret<<1) + b;

        }

        return ret;

