    if ((n & 1) == 1) {

      ans = ans * x;

      ans %= MOD;

    }

    x = x * x;//一周する度にx, x^2, x^4, x^8となる

    x %= MOD;

    n >>= 1; //桁をずらす n = n >> 1

  }

  return ans;

}



